  1→import React, { useEffect, useState } from "react";
  2→import { createPortal } from "react-dom";
  3→import { useInfiniteQuery, useMutation, useQueryClient } from "@tanstack/react-query";
  4→import { useInView } from "react-intersection-observer";
  5→import { useAuth } from "../../../Context/useAuth";
  6→import { deleteProfileMediaImage, getProfileMedia } from "../../../../API/Api";
  7→
  8→const PROFILE_MEDIA_PAGE_SIZE = 5;
  9→
 10→const ProfileMediaSection = () => {
 11→    const { user, session } = useAuth();
 12→    const queryClient = useQueryClient();
 13→    const userId = user?.userData?.[0]?.id;
 14→    const [selectedMedia, setSelectedMedia] = useState(null);
 15→    const [activeMenuId, setActiveMenuId] = useState(null);
 16→    const [deleteCandidate, setDeleteCandidate] = useState(null);
 17→    const { ref: inViewRef, inView } = useInView({ threshold: 0.1 });
 18→
 19→    const { data, isLoading, isError, fetchNextPage, hasNextPage, isFetchingNextPage } = useInfiniteQuery({
 20→        queryKey: ["profileMedia", userId],
 21→        queryFn: ({ pageParam }) => getProfileMedia(session?.access_token, pageParam, PROFILE_MEDIA_PAGE_SIZE),
 22→        initialPageParam: null,
 23→        getNextPageParam: (lastPage) => (lastPage?.hasMore ? lastPage?.nextCursor : undefined),
 24→        enabled: Boolean(userId && session?.access_token),
 25→        refetchOnWindowFocus: false,
 26→        staleTime: 1000 * 60 * 10,
 27→    });
 28→
 29→    const pages = data?.pages ?? [];
 30→    const mediaItems = pages.flatMap((page) => page?.data ?? []);
 31→    const unavailableBuckets = [...new Set(pages.flatMap((page) => page?.unavailableBuckets ?? []))];
 32→    const hasMedia = mediaItems.length > 0;
 33→
 34→    const deleteMediaMutation = useMutation({
 35→        mutationFn: (targetMedia) =>
 36→            deleteProfileMediaImage(session?.access_token, {
 37→                bucket: targetMedia.bucket,
 38→                path: targetMedia.path,
 39→                url: targetMedia.url,
 40→            }),
 41→        onSuccess: (response, targetMedia) => {
 42→            setDeleteCandidate(null);
 43→            setActiveMenuId(null);
 44→
 45→            if (selectedMedia?.id === targetMedia?.id) {
 46→                setSelectedMedia(null);
 47→            }
 48→
 49→            queryClient.setQueryData(["profileMedia", userId], (oldData) => {
 50→                if (!oldData || !Array.isArray(oldData.pages)) {
 51→                    return oldData;
 52→                }
 53→
 54→                return {
 55→                    ...oldData,
 56→                    pages: oldData.pages.map((page) => ({
 57→                        ...page,
 58→                        data: Array.isArray(page?.data) ? page.data.filter((item) => item.id !== targetMedia.id) : page?.data,
 59→                    })),
 60→                };
 61→            });
 62→
 63→            queryClient.invalidateQueries({ queryKey: ["profileMedia", userId] });
 64→
 65→            if (response?.clearedAvatar || response?.clearedBackground) {
 66→                queryClient.invalidateQueries({ queryKey: ["userData"] });
 67→            }
 68→        },
 69→    });
 70→
 71→    const handleOpenMedia = (item) => {
 72→        if (!item?.url) return;
 73→        setSelectedMedia(item);
 74→    };
 75→
 76→    const handleToggleSettingsMenu = (event, mediaId) => {
 77→        event.stopPropagation();
 78→        setActiveMenuId((currentId) => (currentId === mediaId ? null : mediaId));
 79→    };
 80→
 81→    const handleOpenDeleteModal = (event, item) => {
 82→        event.stopPropagation();
 83→        setDeleteCandidate(item);
 84→        setActiveMenuId(null);
 85→    };
 86→
 87→    const handleCloseDeleteModal = () => {
 88→        setDeleteCandidate(null);
 89→    };
 90→
 91→    const handleConfirmDelete = () => {
 92→        if (!deleteCandidate || deleteMediaMutation.isPending) {
 93→            return;
 94→        }
 95→
 96→        deleteMediaMutation.mutate(deleteCandidate);
 97→    };
 98→
 99→    const handleCloseMedia = () => {
100→        setSelectedMedia(null);
101→    };
102→
103→    const profileParentContainer = typeof document !== "undefined" ? document.querySelector(".profile-parent-container") : null;
104→
105→    useEffect(() => {
106→        if (inView && hasNextPage && !isFetchingNextPage) {
107→            fetchNextPage();
108→        }
109→    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage]);
110→
111→    useEffect(() => {
112→        const handleWindowClick = (event) => {
113→            if (!event.target.closest(".profile-media-item-actions")) {
114→                setActiveMenuId(null);
115→            }
116→        };
117→
118→        window.addEventListener("click", handleWindowClick);
119→        return () => window.removeEventListener("click", handleWindowClick);
120→    }, []);
121→
122→    useEffect(() => {
123→        if (!selectedMedia && !deleteCandidate) return;
124→
125→        const handleEscape = (event) => {
126→            if (event.key === "Escape") {
127→                if (deleteCandidate) {
128→                    handleCloseDeleteModal();
129→                    return;
130→                }
131→
132→                handleCloseMedia();
133→            }
134→        };
135→
136→        window.addEventListener("keydown", handleEscape);
137→        return () => window.removeEventListener("keydown", handleEscape);
138→    }, [selectedMedia, deleteCandidate]);
139→
140→    return (
141→        <section className="profile-media-section" aria-label="Profile media">
142→            <div className="profile-media-header-row">
143→                <h2 className="profile-media-heading">
144→                    Posts <span className="profile-media-count">({mediaItems.length})</span>
145→                </h2>
146→            </div>
147→
148→            {unavailableBuckets.length > 0 && <p className="profile-media-warning">Unable to list: {unavailableBuckets.join(", ")}.</p>}
149→
150→            {isLoading && (
151→                <div className="profile-media-grid">
152→                    {Array.from({ length: 9 }).map((_, index) => (
153→                        <div key={`media-loading-${index}`} className="profile-media-grid-item profile-media-grid-loading-item" />
154→                    ))}
155→                </div>
156→            )}
157→
158→            {!isLoading && isError && <p className="profile-media-empty-state">Unable to load your media right now.</p>}
159→
160→            {!isLoading && !isError && !hasMedia && <p className="profile-media-empty-state">No media found in your buckets yet.</p>}
161→
162→            {!isLoading && !isError && hasMedia && (
163→                <div className="profile-media-grid">
164→                    {mediaItems.map((item) => (
165→                        <div key={item.id} className="profile-media-grid-item">
166→                            <button
167→                                className="profile-media-grid-image-button"
168→                                type="button"
169→                                onClick={() => handleOpenMedia(item)}
170→                                title={`View ${item.bucket} image full size`}
171→                            >
172→                                <img className="profile-media-image" src={item.url} alt={`${item.bucket} media`} loading="lazy" />
173→                            </button>
174→                            <div className="profile-media-item-actions">
175→                                <button
176→                                    className="profile-media-item-settings-btn"
177→                                    type="button"
178→                                    onClick={(event) => handleToggleSettingsMenu(event, item.id)}
179→                                    aria-label="Open image settings"
180→                                >
181→                                    <svg xmlns="http://www.w3.org/2000/svg" height="18" viewBox="0 -960 960 960" width="18" fill="currentColor">
182→                                        <path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z" />
183→                                    </svg>
184→                                </button>
185→                                {activeMenuId === item.id && (
186→                                    <div className="profile-media-item-settings-menu" role="menu" aria-label="Image actions">
187→                                        <button className="profile-media-item-delete-btn" type="button" onClick={(event) => handleOpenDeleteModal(event, item)}>
188→                                            Delete image
189→                                        </button>
190→                                    </div>
191→                                )}
192→                            </div>
193→                        </div>
194→                    ))}
195→                    {isFetchingNextPage &&
196→                        Array.from({ length: PROFILE_MEDIA_PAGE_SIZE }).map((_, index) => (
197→                            <div key={`media-loading-next-${index}`} className="profile-media-grid-item profile-media-grid-loading-item" />
198→                        ))}
199→                </div>
200→            )}
201→
202→            {!isLoading && hasMedia && hasNextPage && <div ref={inViewRef} className="profile-media-infinite-sentinel" />}
203→
204→            {selectedMedia &&
205→                profileParentContainer &&
206→                createPortal(
207→                <div className="profile-media-lightbox-overlay" onClick={handleCloseMedia} role="presentation">
208→                    <div className="profile-media-lightbox-dialog" role="dialog" aria-modal="true" aria-label="Full size media preview" onClick={(event) => event.stopPropagation()}>
209→                        <button className="profile-media-lightbox-close" type="button" onClick={handleCloseMedia} aria-label="Close image preview">
210→                            <svg xmlns="http://www.w3.org/2000/svg" height="22" viewBox="0 -960 960 960" width="22" fill="currentColor">
